"use client";

import { useState, useEffect, useCallback } from "react";
import { useRouter } from "next/navigation";
import { useQueryClient } from "@tanstack/react-query";
import { useCartStore } from "@/stores/cartStore";
import { useAuthStore } from "@/stores/authStore";
import { useTableStore } from "@/stores/tableStore";
import { useOrderModeStore } from "@/stores/orderModeStore";
import { useToast } from "@/components/ui/Toast";
import {
  createOrder,
  getTableByNumber,
  getRestaurantStatus,
  getActiveOrder,
  addItemsToOrder,
  createDeliveryOrder,
  createTakeawayOrder,
  createDineInOrder,
  getPublicTableOrders,
  type PublicTableOrders,
} from "@/lib/api";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Icon } from "@/components/ui/Icon";
import { DeliveryForm, TableNumberInput, TakeawayConfirm } from "@/components/order";
import type { Order } from "@/types";

type Step = "phone" | "otp" | "details";

export default function CheckoutPage() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { showToast } = useToast();
  const { items, getSubtotal, getTax, getTotal, clearCart } = useCartStore();
  const { isAuthenticated, sendOtp, verifyOtp, isLoading, error, clearError, phone: authPhone, checkAuth } =
    useAuthStore();
  const { tableId, tableNumber, menuId, restaurantId: tableRestaurantId, onlinePaymentAvailable } = useTableStore();
  const {
    mode,
    selectedRestaurantId,
    selectedRestaurantName,
    deliveryAddress,
    tableNumber: modeTableNumber,
    customerName,
    customerPhone,
    deliveryFee,
    setCustomerPhone,
    clearMode,
  } = useOrderModeStore();

  // Determine the effective restaurant ID
  const restaurantId = mode === "qr" ? tableRestaurantId : selectedRestaurantId;

  // Build QR-aware URL
  const getMenuUrl = useCallback(() => {
    if (mode === "qr" && tableNumber) {
      return `/menu?table=${tableNumber}${menuId ? `&menu=${menuId}` : ''}`;
    }
    return "/menu";
  }, [mode, tableNumber, menuId]);

  const getOrdersUrl = useCallback(() => {
    if (mode === "qr" && tableNumber) {
      return `/orders?table=${tableNumber}${menuId ? `&menu=${menuId}` : ''}`;
    }
    return "/orders";
  }, [mode, tableNumber, menuId]);

  // Navigate to menu with QR params preserved
  const navigateToMenu = useCallback(() => {
    router.push(getMenuUrl());
  }, [router, getMenuUrl]);

  // Navigate to orders with QR params preserved
  const navigateToOrders = useCallback(() => {
    router.push(getOrdersUrl());
  }, [router, getOrdersUrl]);

  // Determine initial step based on mode and authentication
  const getInitialStep = (): Step => {
    // If not authenticated, ALWAYS start at phone input
    if (!isAuthenticated) return "phone";
    // For QR mode when already authenticated, start at "phone" step
    // The useEffect will immediately trigger auto-submit
    if (mode === "qr") return "phone";
    return "details";
  };

  // Track if we're auto-submitting for authenticated QR users
  const [isAutoSubmitting, setIsAutoSubmitting] = useState(false);

  const [step, setStep] = useState<Step>(getInitialStep);
  const [phone, setPhone] = useState("");
  const [otp, setOtp] = useState("");
  const [specialInstructions, setSpecialInstructions] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitError, setSubmitError] = useState<string | null>(null);

  // Pause modal state
  const [showPauseModal, setShowPauseModal] = useState(false);
  const [pauseMessage, setPauseMessage] = useState("");

  // Public table orders (for showing existing orders before auth)
  const [publicOrders, setPublicOrders] = useState<PublicTableOrders | null>(null);

  // Check token expiration on mount
  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  // Check restaurant status
  useEffect(() => {
    const checkRestaurantStatus = async () => {
      if (restaurantId) {
        try {
          const status = await getRestaurantStatus(restaurantId);
          if (!status.acceptingOrders) {
            setShowPauseModal(true);
            setPauseMessage(status.pauseMessage || "");
          }
        } catch (error) {
          console.error("Error checking restaurant status:", error);
        }
      }
    };
    checkRestaurantStatus();
  }, [restaurantId]);

  // Load public table orders for QR mode (always load to get serviceFeePercent)
  useEffect(() => {
    const loadPublicOrders = async () => {
      if (mode === "qr" && tableId) {
        try {
          const data = await getPublicTableOrders(tableId);
          setPublicOrders(data);
        } catch {
          setPublicOrders(null);
        }
      }
    };
    loadPublicOrders();
  }, [mode, tableId]);

  // Update step when authentication changes
  useEffect(() => {
    if (!isAuthenticated) {
      // If the user loses authentication (e.g. storage cleared) while on the final details screen,
      // forcefully step back to phone. But do NOT interrupt if they are typing OTP!
      if (step === "details") {
        setStep("phone");
      }
      setIsAutoSubmitting(false);
    } else if (isAuthenticated && step === "phone") {
      // QR mode: submit order directly when authenticated (no OTP needed again)
      if (mode === "qr") {
        setIsAutoSubmitting(true);
        handleSubmitOrder();
      } else {
        setStep("details");
      }
    }
  }, [isAuthenticated, step, mode]);

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("ru-RU").format(price);
  };

  const formatPhone = (value: string) => {
    const digits = value.replace(/\D/g, "");
    let formatted = "";
    if (digits.length > 0) {
      formatted = "+992";
      if (digits.length > 3) {
        formatted += " " + digits.slice(3, 5);
        if (digits.length > 5) {
          formatted += " " + digits.slice(5, 8);
          if (digits.length > 8) {
            formatted += "-" + digits.slice(8, 10);
            if (digits.length > 10) {
              formatted += "-" + digits.slice(10, 12);
            }
          }
        }
      }
    }
    return formatted;
  };

  const handlePhoneChange = (value: string) => {
    const digits = value.replace(/\D/g, "");
    if (digits.length <= 12) {
      setPhone(formatPhone(digits.startsWith("992") ? digits : "992" + digits));
    }
  };

  const handleSendOtp = async () => {
    const digits = phone.replace(/\D/g, "");
    if (digits.length !== 12) return;

    clearError();
    try {
      await sendOtp("+" + digits);
      setStep("otp");
    } catch {
      // Error is handled in store
    }
  };

  const handleVerifyOtp = async () => {
    if (otp.length !== 4) return;

    const digits = phone.replace(/\D/g, "");
    clearError();
    try {
      await verifyOtp("+" + digits, otp);
      setCustomerPhone("+" + digits);

      // For QR mode, submit order directly after OTP verification
      if (mode === "qr") {
        await handleSubmitOrder();
      } else {
        setStep("details");
      }
    } catch {
      // Error is handled in store
    }
  };

  const handleDetailsBack = () => {
    router.push("/");
  };

  // Handle order completion - always redirect to orders page
  const handlePaymentRedirect = (order: Order) => {
    // Invalidate the orders cache so the orders page shows fresh data
    queryClient.invalidateQueries({ queryKey: ["orders"] });
    // Всегда редирект на страницу заказов (без редиректа в банк)
    showToast("Заказ оформлен!", "success");
    navigateToOrders();
  };

  const handleSubmitOrder = async (dineInTableNumber?: number) => {
    setIsSubmitting(true);
    setSubmitError(null);

    try {
      const orderItems = items.map((item) => ({
        productId: item.productId,
        sizeId: item.sizeId,
        quantity: item.quantity,
        addonIds: item.addonIds.length > 0 ? item.addonIds : undefined,
        note: item.note || undefined,
      }));

      if (mode === "delivery") {
        if (!selectedRestaurantId) {
          setSubmitError("Ресторан не выбран");
          setIsSubmitting(false);
          return;
        }
        if (!deliveryAddress) {
          setSubmitError("Адрес доставки не указан");
          setIsSubmitting(false);
          return;
        }

        const order = await createDeliveryOrder({
          restaurantId: selectedRestaurantId,
          items: orderItems,
          deliveryAddress,
          customerName: customerName || "Гость",
          customerPhone: customerPhone || authPhone || "",
          specialInstructions: specialInstructions || undefined,
        });

        clearCart();
        clearMode();
        // Redirect to payment for delivery
        handlePaymentRedirect(order);
      } else if (mode === "takeaway") {
        if (!selectedRestaurantId) {
          setSubmitError("Ресторан не выбран");
          setIsSubmitting(false);
          return;
        }

        const order = await createTakeawayOrder({
          restaurantId: selectedRestaurantId,
          items: orderItems,
          customerName: customerName || "Гость",
          customerPhone: customerPhone || authPhone || "",
          specialInstructions: specialInstructions || undefined,
        });

        clearCart();
        clearMode();
        // Redirect to payment for takeaway
        handlePaymentRedirect(order);
      } else if (mode === "dinein" && selectedRestaurantId && (dineInTableNumber || modeTableNumber)) {
        const tableNum = dineInTableNumber || modeTableNumber;
        const order = await createDineInOrder({
          restaurantId: selectedRestaurantId,
          tableNumber: tableNum!,
          items: orderItems,
          specialInstructions: specialInstructions || undefined,
        });

        clearCart();
        clearMode();
        // Redirect to payment for dinein
        handlePaymentRedirect(order);
      } else {
        // QR mode (original flow)
        // Try zustand store first, fallback to sessionStorage for hydration edge cases
        let effectiveTableId = tableId;
        let effectiveTableNumber = tableNumber;

        // Always check sessionStorage if any value is missing
        if (typeof window !== "undefined" && (!effectiveTableId || !effectiveTableNumber)) {
          try {
            const tableStorage = sessionStorage.getItem("table-storage-v2");
            if (tableStorage) {
              const parsed = JSON.parse(tableStorage);
              if (parsed.state) {
                if (!effectiveTableId) {
                  effectiveTableId = parsed.state.tableId;
                }
                if (!effectiveTableNumber) {
                  effectiveTableNumber = parsed.state.tableNumber;
                }
              }
            }
          } catch (e) {
            console.warn("Failed to read from sessionStorage:", e);
          }
        }

        if (!effectiveTableId && !effectiveTableNumber) {
          setSubmitError("Стол не определён. Отсканируйте QR-код.");
          setIsSubmitting(false);
          return;
        }

        let resolvedTableId = effectiveTableId;

        if (!effectiveTableId || effectiveTableId.startsWith("table-")) {
          if (!effectiveTableNumber) {
            setSubmitError("Стол не определён. Отсканируйте QR-код.");
            setIsSubmitting(false);
            return;
          }
          try {
            const table = await getTableByNumber(effectiveTableNumber);
            resolvedTableId = table.id;
          } catch {
            setSubmitError("Не удалось найти стол. Попробуйте отсканировать QR-код снова.");
            setIsSubmitting(false);
            return;
          }
        }

        let activeOrder: Order | null = null;
        try {
          activeOrder = await getActiveOrder(resolvedTableId!);
        } catch {
          // No active order or error - will create new
        }

        let order: Order;
        if (activeOrder && activeOrder.status !== "Cancelled") {
          order = await addItemsToOrder(activeOrder.id, orderItems);
        } else {
          order = await createOrder({
            tableId: resolvedTableId!,
            specialInstructions: specialInstructions || undefined,
            items: orderItems,
          });
        }

        clearCart();
        // Redirect to payment for QR mode
        handlePaymentRedirect(order);
      }
    } catch (err: unknown) {
      const error = err as { response?: { data?: { error?: string } }; message?: string };
      const errorMsg = error.response?.data?.error || error.message || "Неизвестная ошибка";
      setSubmitError(`Ошибка: ${errorMsg}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Redirect to orders if cart is empty
  useEffect(() => {
    if (items.length === 0) {
      router.push(getOrdersUrl());
    }
  }, [items.length, router, getOrdersUrl]);

  if (items.length === 0) {
    return null;
  }

  const getStepTitle = () => {
    switch (step) {
      case "phone": return "Авторизация";
      case "otp": return mode === "qr" ? "Подтверждение заказа" : "Подтверждение";
      case "details": return mode === "delivery" ? "Адрес доставки" : mode === "dinein" ? "Номер стола" : mode === "takeaway" ? "Самовывоз" : "Оформление";
      default: return "Оформление";
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-primary-light via-white to-primary-light/30">
      {/* Header */}
      <header className="sticky top-0 bg-white/95 backdrop-blur-sm border-b border-gray-100 z-40">
        <div className="flex items-center h-14 px-4">
          <button onClick={() => router.back()} className="mr-4 p-2 -ml-2 rounded-full hover:bg-gray-100 transition-colors">
            <Icon name="arrow_back" size={24} className="text-gray-700" />
          </button>
          <h1 className="text-lg font-bold text-gray-800">{getStepTitle()}</h1>
        </div>
      </header>

      <div className="p-4 space-y-6 max-w-md mx-auto">
        {/* Steps indicator - 2 steps for QR mode, 3 steps for other modes */}
        {(() => {
          // QR mode has only 2 steps (phone, otp), other modes have 3 (phone, otp, details)
          const steps: Step[] = mode === "qr" ? ["phone", "otp"] : ["phone", "otp", "details"];
          const currentIndex = steps.indexOf(step);

          return (
            <div className="flex items-center justify-center gap-2 py-4">
              {steps.map((s, i) => (
                <div key={s} className="flex items-center">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm shadow-sm transition-all ${
                    step === s
                      ? "bg-[#dda15e] text-[#1b4332] shadow-[0_4px_10px_rgba(221,161,94,0.3)]"
                      : i < currentIndex
                      ? "bg-gradient-to-br from-[#1b4332] to-[#14532d] text-white shadow-md shadow-[#1b4332]/20"
                      : "bg-white text-gray-400 border border-gray-200"
                  }`}>
                    {i < currentIndex ? <Icon name="check" size={18} /> : i + 1}
                  </div>
                  {i < steps.length - 1 && (
                    <div className={`w-8 h-1 mx-1 rounded-full ${i < currentIndex ? "bg-[#1b4332]" : "bg-gray-200"}`} />
                  )}
                </div>
              ))}
            </div>
          );
        })()}

        {/* Phone step */}
        {step === "phone" && (
          <div className="space-y-6">
            {/* Auto-submitting state for authenticated QR users */}
            {isAutoSubmitting ? (
              <div className="text-center py-12">
                <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-[#1b4332] to-[#14532d] flex items-center justify-center mx-auto mb-4 shadow-lg shadow-[#1b4332]/20 animate-pulse">
                  <Icon name="receipt_long" size={40} className="text-[#dda15e]" />
                </div>
                <h2 className="text-xl font-bold text-gray-800 mb-2">Оформляем заказ...</h2>
                <p className="text-gray-500">Пожалуйста, подождите</p>
                {submitError && (
                  <div className="mt-4 bg-red-50 border border-red-100 rounded-xl p-3 flex items-center gap-2">
                    <Icon name="error" size={20} className="text-red-500" />
                    <p className="text-red-600 text-sm">{submitError}</p>
                  </div>
                )}
              </div>
            ) : (
              <>
                {/* Show existing table orders for QR mode */}
                {mode === "qr" && publicOrders?.hasActiveSession && (
                  <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100">
                    <div className="flex items-center gap-3 mb-2">
                      <div className="w-10 h-10 rounded-xl bg-blue-100 flex items-center justify-center">
                        <Icon name="group" size={20} className="text-blue-500" />
                      </div>
                      <div>
                        <p className="font-semibold text-blue-800">
                          {publicOrders.guestCount} {publicOrders.guestCount === 1 ? "гость" : publicOrders.guestCount < 5 ? "гостя" : "гостей"} уже заказали
                        </p>
                        <p className="text-sm text-blue-600">
                          Общий счёт: {formatPrice(publicOrders.tableTotal)} TJS
                        </p>
                      </div>
                    </div>
                    <p className="text-sm text-blue-600 mt-2">
                      Ваш заказ добавится к общему счёту стола
                    </p>
                  </div>
                )}

                <div className="text-center">
                  <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-primary-300 to-primary flex items-center justify-center mx-auto mb-4 shadow-lg shadow-primary-200">
                    <Icon name="phone_iphone" size={40} className="text-white" />
                  </div>
                  <h2 className="text-2xl font-bold text-gray-800 mb-2">Введите номер телефона</h2>
                  <p className="text-gray-500">Мы отправим SMS с кодом подтверждения</p>
                </div>

                <div className="bg-white rounded-2xl p-4 border border-gray-100 shadow-sm">
                  <Input
                    type="tel"
                    value={phone}
                    onChange={(e) => handlePhoneChange(e.target.value)}
                    placeholder="+992"
                    className="text-center text-xl font-medium"
                    error={error || undefined}
                  />
                </div>

                <Button
                  onClick={handleSendOtp}
                  className="w-full"
                  variant="navy"
                  size="lg"
                  isLoading={isLoading}
                  disabled={phone.replace(/\D/g, "").length !== 12}
                >
                  <Icon name="send" size={20} className="mr-2 text-[#dda15e]" />
                  Получить код
                </Button>
              </>
            )}
          </div>
        )}

        {/* OTP step */}
        {step === "otp" && (
          <div className="space-y-6">
            {/* Show existing table orders for QR mode */}
            {mode === "qr" && publicOrders?.hasActiveSession && (
              <div className="bg-blue-50 p-3 rounded-xl border border-blue-100 text-center">
                <p className="text-sm text-blue-700">
                  <span className="font-medium">{publicOrders.guestCount} {publicOrders.guestCount === 1 ? "гость" : "гостей"}</span> уже за столом •
                  Счёт: <span className="font-medium">{formatPrice(publicOrders.tableTotal)} TJS</span>
                </p>
              </div>
            )}

            <div className="text-center">
              <div className={`w-20 h-20 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg ${
                mode === "qr"
                  ? "bg-gradient-to-br from-[#1b4332] to-[#14532d] shadow-[#1b4332]/20"
                  : "bg-gradient-to-br from-[#1b4332] to-[#14532d] shadow-[#1b4332]/20"
              }`}>
                <Icon name={mode === "qr" ? "receipt_long" : "sms"} size={40} className="text-white" />
              </div>
              <h2 className="text-2xl font-bold text-gray-800 mb-2">Введите код из SMS</h2>
              <p className="text-gray-500">Код отправлен на {phone}</p>
              {mode === "qr" && (
                <p className="text-sm text-[#1b4332] mt-2 font-medium">
                  После подтверждения заказ будет оформлен
                </p>
              )}
            </div>

            <div className="bg-white rounded-2xl p-4 border border-gray-100 shadow-sm">
              <Input
                type="text"
                value={otp}
                onChange={(e) => setOtp(e.target.value.replace(/\D/g, "").slice(0, 4))}
                placeholder="• • • •"
                className="text-center text-3xl tracking-[0.5em] font-bold"
                error={error || submitError || undefined}
                maxLength={4}
              />
            </div>

            <p className="text-center text-sm text-gray-400">Код придёт по SMS в течение минуты</p>

            {submitError && mode === "qr" && (
              <div className="bg-red-50 border border-red-100 rounded-xl p-3 flex items-center gap-2">
                <Icon name="error" size={20} className="text-red-500" />
                <p className="text-red-600 text-sm">{submitError}</p>
              </div>
            )}

            <div className="space-y-3">
              <Button
                onClick={handleVerifyOtp}
                className="w-full"
                variant="navy"
                size="lg"
                isLoading={isLoading || isSubmitting}
                disabled={otp.length !== 4}
              >
                <Icon name={mode === "qr" ? "check_circle" : "verified"} size={20} className="mr-2 text-[#dda15e]" />
                {mode === "qr" ? "Подтвердить заказ" : "Подтвердить"}
              </Button>
              <Button onClick={() => setStep("phone")} variant="ghost" className="w-full" disabled={isSubmitting}>
                <Icon name="edit" size={18} className="mr-2" />
                Изменить номер
              </Button>
            </div>
          </div>
        )}

        {/* Details step - now includes submit */}
        {step === "details" && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
            {mode === "delivery" && (
              <DeliveryForm
                onSubmit={handleSubmitOrder}
                onBack={handleDetailsBack}
                isSubmitting={isSubmitting}
                submitError={submitError}
              />
            )}
            {mode === "dinein" && (
              <TableNumberInput
                onSubmit={(tableNum) => handleSubmitOrder(tableNum)}
                onBack={handleDetailsBack}
                isSubmitting={isSubmitting}
                submitError={submitError}
              />
            )}
            {mode === "takeaway" && (
              <TakeawayConfirm
                onSubmit={handleSubmitOrder}
                onBack={handleDetailsBack}
                isSubmitting={isSubmitting}
                submitError={submitError}
              />
            )}
            {mode === "qr" && (
              <div className="space-y-5">
                <div className="text-center">
                  <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-[#1b4332] to-[#14532d] flex items-center justify-center mx-auto mb-3 shadow-lg shadow-[#1b4332]/20">
                    <Icon name="receipt_long" size={32} className="text-[#dda15e]" />
                  </div>
                  <h2 className="text-xl font-bold text-gray-800">Подтвердите заказ</h2>
                </div>

                {/* Order summary for QR mode */}
                <div className="bg-white rounded-2xl p-4 space-y-3 border border-gray-100 shadow-sm">
                  <h3 className="font-semibold text-gray-800 flex items-center gap-2">
                    <Icon name="shopping_bag" size={18} className="text-primary" />
                    Ваш заказ
                  </h3>
                  <div className="space-y-2">
                    {items.map((item) => (
                      <div key={item.id} className="flex justify-between text-sm py-1">
                        <span className="text-gray-600 flex-1">
                          {item.productName} <span className="text-gray-400">x{item.quantity}</span>
                          {item.sizeName && <span className="text-gray-400"> ({item.sizeName})</span>}
                        </span>
                        <span className="text-gray-800 font-medium ml-2">{formatPrice(item.totalPrice)} TJS</span>
                      </div>
                    ))}
                  </div>
                  <div className="border-t border-gray-100 pt-3 space-y-2">
                    <div className="flex justify-between text-sm text-gray-500">
                      <span>Подитог</span>
                      <span>{formatPrice(getSubtotal())} TJS</span>
                    </div>
                    {(() => {
                      const serviceFeePercent = publicOrders?.serviceFeePercent ?? 10;
                      const serviceFee = Math.round(getSubtotal() * serviceFeePercent / 100);
                      const total = getSubtotal() + serviceFee;
                      return (
                        <>
                          <div className="flex justify-between text-sm text-gray-500">
                            <span>Обслуживание ({serviceFeePercent}%)</span>
                            <span>{formatPrice(serviceFee)} TJS</span>
                          </div>
                          <div className="flex justify-between font-bold text-lg text-gray-800 pt-2 border-t border-gray-100">
                            <span>Итого</span>
                            <span className="text-primary">{formatPrice(total)} TJS</span>
                          </div>
                        </>
                      );
                    })()}
                  </div>
                </div>

                {/* Payment info */}
                <div className="bg-blue-50 border-blue-100 rounded-2xl p-4 border">
                  <div className="flex items-start gap-3">
                    <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 bg-blue-100">
                      <Icon name="info" size={20} className="text-blue-500" />
                    </div>
                    <div>
                      <p className="text-sm font-medium text-blue-800">Способ оплаты</p>
                      <p className="text-sm mt-1 text-blue-600">
                        После подтверждения заказа вы сможете выбрать способ оплаты: наличными или картой DC
                      </p>
                    </div>
                  </div>
                </div>

                {/* Special instructions */}
                <div>
                  <label className="block text-sm font-medium text-gray-600 mb-2">
                    Комментарий к заказу
                  </label>
                  <textarea
                    value={specialInstructions}
                    onChange={(e) => setSpecialInstructions(e.target.value)}
                    placeholder="Например: без лука, острый соус отдельно..."
                    className="w-full px-4 py-3 bg-white border border-gray-200 rounded-xl text-gray-800 placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent resize-none shadow-sm transition-all"
                    rows={2}
                  />
                </div>
                

                {submitError && (
                  <div className="bg-red-50 border border-red-100 rounded-xl p-3 flex items-center gap-2">
                    <Icon name="error" size={20} className="text-red-500" />
                    <p className="text-red-600 text-sm">{submitError}</p>
                  </div>
                )}

                <Button
                  onClick={() => handleSubmitOrder()}
                  className="w-full"
                  variant="navy"
                  size="lg"
                  isLoading={isSubmitting}
                >
                  <Icon name="check_circle" size={22} className="mr-2 text-[#dda15e]" />
                  Подтвердить заказ
                </Button>

                <Button onClick={handleDetailsBack} variant="ghost" className="w-full">
                  <Icon name="arrow_back" size={18} className="mr-2" />
                  Назад
                </Button>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Pause modal */}
      {showPauseModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl w-full max-w-sm p-6 text-center shadow-2xl">
            <div className="w-16 h-16 bg-primary-light rounded-2xl flex items-center justify-center mx-auto mb-4">
              <Icon name="pause_circle" size={40} className="text-primary" />
            </div>
            <h2 className="text-xl font-bold text-gray-800 mb-2">Приём заказов приостановлен</h2>
            <p className="text-gray-500 mb-4">
              {pauseMessage || "Ресторан временно не принимает заказы. Пожалуйста, попробуйте позже."}
            </p>
            <div className="space-y-3">
              <Button onClick={() => setShowPauseModal(false)} variant="outline" className="w-full">
                Понятно
              </Button>
              <Button onClick={navigateToMenu} variant="secondary" className="w-full">
                Вернуться в меню
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
